class Solution:
    def findPermutation(self, nums):
        n = len(nums)
        from itertools import permutations
        best_cost = float('inf')
        best_perm = None
        for perm in permutations(range(n)):
            cost = sum(abs(perm[i] - nums[perm[(i+1) % n]]) for i in range(n))
            if cost < best_cost or (cost == best_cost and list(perm) < list(best_perm)):
                best_cost = cost
                best_perm = list(perm)
        return best_perm

