var findPermutation = function(nums) {
    const n = nums.length;
    const INF = Infinity;
    const full = (1 << n) - 1;
    // dp[mask][last]
    const dp = Array.from({length: 1 << n}, () => new Array(n).fill(INF));
    dp[1][0] = 0;
    for (let mask = 1; mask < (1 << n); mask++) {
        for (let last = 0; last < n; last++) {
            if (dp[mask][last] === INF) continue;
            if (!(mask >> last & 1)) continue;
            for (let nxt = 0; nxt < n; nxt++) {
                if (mask >> nxt & 1) continue;
                const newMask = mask | (1 << nxt);
                const cost = dp[mask][last] + Math.abs(last - nums[nxt]);
                if (cost < dp[newMask][nxt]) dp[newMask][nxt] = cost;
            }
        }
    }
    // mtc[mask][last] = min cost to complete from last back to 0
    const mtc = Array.from({length: 1 << n}, () => new Array(n).fill(INF));
    for (let last = 0; last < n; last++) {
        if (dp[full][last] < INF) mtc[full][last] = Math.abs(last - nums[0]);
    }
    for (let mask = full - 1; mask > 0; mask--) {
        for (let last = 0; last < n; last++) {
            if (!(mask >> last & 1)) continue;
            for (let nxt = 0; nxt < n; nxt++) {
                if (mask >> nxt & 1) continue;
                const newMask = mask | (1 << nxt);
                const cost = Math.abs(last - nums[nxt]) + mtc[newMask][nxt];
                if (cost < mtc[mask][last]) mtc[mask][last] = cost;
            }
        }
    }
    // Greedy lex reconstruction
    const perm = [0];
    let curMask = 1, cur = 0;
    for (let step = 0; step < n - 1; step++) {
        let bestNxt = -1, bestC = INF;
        for (let nxt = 0; nxt < n; nxt++) {
            if (curMask >> nxt & 1) continue;
            const newMask = curMask | (1 << nxt);
            const total = Math.abs(cur - nums[nxt]) + mtc[newMask][nxt];
            if (total < bestC || (total === bestC && nxt < bestNxt)) {
                bestC = total; bestNxt = nxt;
            }
        }
        perm.push(bestNxt);
        curMask |= (1 << bestNxt);
        cur = bestNxt;
    }
    return perm;
};
